# -*- coding: utf-8 -*-
from django.db import models
from django.utils.translation import gettext_lazy as _

from ralph.assets.models.assets import Asset
from ralph.assets.models.components import Component
from ralph.lib.mixins.fields import NullableCharField
from ralph.lib.mixins.models import AdminAbsoluteUrlMixin


class DiskShare(Component):
    share_id = models.PositiveIntegerField(
        verbose_name=_("share identifier"),
        null=True,
        blank=True,
    )
    label = models.CharField(
        verbose_name=_("name"),
        max_length=255,
        blank=True,
        null=True,
        default=None,
    )
    size = models.PositiveIntegerField(
        verbose_name=_("size (MiB)"),
        null=True,
        blank=True,
    )
    snapshot_size = models.PositiveIntegerField(
        verbose_name=_("size for snapshots (MiB)"),
        null=True,
        blank=True,
    )
    wwn = NullableCharField(
        verbose_name=_("Volume serial"),
        max_length=33,
        unique=True,
    )
    full = models.BooleanField(default=True)

    def get_total_size(self):
        return (self.size or 0) + (self.snapshot_size or 0)

    class Meta:
        verbose_name = _("disk share")
        verbose_name_plural = _("disk shares")

    def __str__(self):
        return "%s (%s)" % (self.label, self.wwn)


class DiskShareMount(AdminAbsoluteUrlMixin, models.Model):
    share = models.ForeignKey(
        DiskShare, verbose_name=_("share"), on_delete=models.CASCADE
    )
    asset = models.ForeignKey(
        Asset,
        verbose_name=_("asset"),
        null=True,
        blank=True,
        default=None,
        on_delete=models.SET_NULL,
    )
    volume = models.CharField(
        verbose_name=_("volume"), max_length=255, blank=True, null=True, default=None
    )
    size = models.PositiveIntegerField(
        verbose_name=_("size (MiB)"),
        null=True,
        blank=True,
    )

    def get_total_mounts(self):
        return (
            self.share.disksharemount_set.exclude(device=None)
            .filter(is_virtual=False)
            .count()
        )

    def get_size(self):
        return self.size or self.share.get_total_size()

    class Meta:
        unique_together = ("share", "asset")
        verbose_name = _("disk share mount")
        verbose_name_plural = _("disk share mounts")

    def __str__(self):
        return "%s@%r" % (self.volume, self.asset)

from django.contrib.auth.decorators import login_required, permission_required
from django.http import JsonResponse
from django.shortcuts import get_object_or_404, render
from django.views.decorators.cache import never_cache
from markdown import markdown

from releases.models import Release

from .models import (
    BugFixRelease,
    FeatureRelease,
    PreRelease,
    SecurityIssue,
    SecurityRelease,
)


@never_cache
def render_checklist(request, instance):
    raw_markdown = instance.render_to_string(request=request)
    markdown_content = markdown(
        raw_markdown,
        output_format="html",
        extensions=[
            "pymdownx.extra",
            "pymdownx.tasklist",
            "pymdownx.superfences",
            "pymdownx.magiclink",
            "markdown.extensions.fenced_code",
        ],
        extension_configs={
            "pymdownx.tasklist": {
                "custom_checkbox": True,
                "clickable_checkbox": True,
            },
        },
    )
    return render(
        request,
        "checklists/checklist_detail.html",
        {
            "instance": instance,
            "markdown": markdown_content,
            "raw_markdown": raw_markdown,
        },
    )


@never_cache
def release_checklist(request, version):
    release = get_object_or_404(Release, version=version)
    if release.is_pre_release:
        checklist_model = PreRelease
    elif release.is_dot_zero:
        checklist_model = FeatureRelease
    else:
        checklist_model = BugFixRelease
    instance = get_object_or_404(checklist_model, release__version=version)
    return render_checklist(request, instance)


@never_cache
@login_required
@permission_required(
    ["checklists.view_securityrelease", "checklists.view_securityissue"],
    raise_exception=True,
)
def securityrelease_checklist(request, pk):
    instance = get_object_or_404(SecurityRelease, pk=pk)
    return render_checklist(request, instance)


@never_cache
@login_required
@permission_required("checklists.view_securityissue", raise_exception=True)
def cve_json_record(request, cve_id):
    issue = get_object_or_404(SecurityIssue, cve_year_number=cve_id)
    response = JsonResponse(issue.cve_data)
    response["Content-Disposition"] = f'inline; filename="{cve_id}.json"'
    return response

import re

from django.template import Library
from django.template.defaultfilters import stringfilter
from django.utils import timezone
from django.utils.html import conditional_escape
from django.utils.safestring import mark_safe

register = Library()


def _no_op(x):
    return x


def _esc_func(autoescape):
    if autoescape:
        return conditional_escape
    return _no_op


@stringfilter
def spacify(value, autoescape=None):
    esc = _esc_func(autoescape)
    val = esc(value).replace(' ', "&nbsp;")
    val = val.replace('\t', '    ')
    return mark_safe(val)


def _urlify(str):
    r = re.compile(r'"(?P<src>.*\.py)", line (?P<num>[0-9]+).*')
    m = r.search(str)
    while m:
        group = m.groupdict()
        src = group['src']
        num = group['num']
        start = m.start('src')
        end = m.end('src')
        rep = '<a href="/silk/src/?file_path={src}&line_num={num}">{src}</a>'.format(src=src, num=num)
        str = str[:start] + rep + str[end:]
        m = r.search(str)
    return str


@register.filter
def hash(h, key):
    return h[key]


def _process_microseconds(dt_strftime):
    splt = dt_strftime.split('.')
    micro = splt[-1]
    time = '.'.join(splt[0:-1])
    micro = '%.3f' % float('0.' + micro)
    return time + micro[1:]


def _silk_date_time(dt):
    today = timezone.now().date()
    if dt.date() == today:
        dt_strftime = dt.strftime('%H:%M:%S.%f')
        return _process_microseconds(dt_strftime)
    else:
        return _process_microseconds(dt.strftime('%Y.%m.%d %H:%M.%f'))


@register.filter(expects_localtime=True)
def silk_date_time(dt):
    return _silk_date_time(dt)


@register.filter
def sorted(value):
    return sorted(value)


@stringfilter
def filepath_urlify(value, autoescape=None):
    value = _urlify(value)
    return mark_safe(value)


@stringfilter
def body_filter(value):
    print(value)
    if len(value) > 20:
        return 'Too big!'
    else:
        return value


spacify.needs_autoescape = True
filepath_urlify.needs_autoescape = True
register.filter(spacify)
register.filter(filepath_urlify)
register.filter(body_filter)

