from rest_framework.exceptions import ValidationError

from users.models import User, create_token_if_necessary


class PublicUserSerializer(serializers.HyperlinkedModelSerializer):
    class Meta:
        model = User
        fields = (
            'username',
            'gravatar',
            settings.DRF_URL_FIELD_NAME,
        )
        extra_kwargs = {
            settings.DRF_URL_FIELD_NAME: {
                "view_name": "public-users:user-detail",
            },
        }


class UserSerializer(serializers.HyperlinkedModelSerializer):
    class Meta:
        model = User
        fields = (
            'username',
            'token',
            'email',
            'gravatar',
            'password',
            'password_repeat',
            settings.DRF_URL_FIELD_NAME,
        )
        extra_kwargs = {
            settings.DRF_URL_FIELD_NAME: {
                "view_name": "users:user-detail",
            },
        }

    password = serializers.CharField(
        write_only=True,
        required=True,
        allow_blank=False,
        min_length=6,
        max_length=32,
    )
    password_repeat = serializers.CharField(
        write_only=True,
        required=True,
        allow_blank=False,
        min_length=6,
        max_length=32,
    )
    token = serializers.SerializerMethodField(read_only=True)

    def create(self, validated_data):
        if validated_data['password'] != validated_data['password_repeat']:
            raise ValidationError(
                detail={
                    "password_repeat": "Tow password doesn't match",
                }
            )
        validated_data.pop('password_repeat')
        password = validated_data.pop('password')
        user = super(UserSerializer, self).create(
            validated_data,
        )
        user.set_password(password)
        user.save()
        login(
            self.context['request'],
            user=user,
            backend=settings.AUTHENTICATION_BACKENDS[0],
        )
        return user

    def get_token(self, obj: User):
        if self.context['request'].user == obj:
            return create_token_if_necessary(obj).key
        return None

from typing import Annotated

from django.conf import settings
from django.http import HttpRequest, HttpResponse
from pydantic import StringConstraints

from zerver.actions.saved_snippets import (
    do_create_saved_snippet,
    do_delete_saved_snippet,
    do_edit_saved_snippet,
    do_get_saved_snippets,
)
from zerver.lib.response import json_success
from zerver.lib.typed_endpoint import PathOnly, typed_endpoint
from zerver.models import SavedSnippet, UserProfile


def get_saved_snippets(
    request: HttpRequest,
    user_profile: UserProfile,
) -> HttpResponse:
    return json_success(request, data={"saved_snippets": do_get_saved_snippets(user_profile)})


@typed_endpoint
def create_saved_snippet(
    request: HttpRequest,
    user_profile: UserProfile,
    *,
    content: Annotated[
        str,
        StringConstraints(
            min_length=1, max_length=settings.MAX_MESSAGE_LENGTH, strip_whitespace=True
        ),
    ],
    title: Annotated[
        str,
        StringConstraints(
            min_length=1, max_length=SavedSnippet.MAX_TITLE_LENGTH, strip_whitespace=True
        ),
    ],
) -> HttpResponse:
    title = title.strip()
    content = content.strip()
    saved_snippet = do_create_saved_snippet(title, content, user_profile)
    return json_success(request, data={"saved_snippet_id": saved_snippet.id})


@typed_endpoint
def edit_saved_snippet(
    request: HttpRequest,
    user_profile: UserProfile,
    *,
    content: Annotated[
        str | None,
        StringConstraints(
            min_length=1, max_length=settings.MAX_MESSAGE_LENGTH, strip_whitespace=True
        ),
    ] = None,
    saved_snippet_id: PathOnly[int],
    title: Annotated[
        str | None,
        StringConstraints(
            min_length=1, max_length=SavedSnippet.MAX_TITLE_LENGTH, strip_whitespace=True
        ),
    ] = None,
) -> HttpResponse:
    if title is None and content is None:
        # No changes are requested; exit early to avoid sending a
        # spurious event to clients.
        return json_success(request)

    do_edit_saved_snippet(saved_snippet_id, title, content, user_profile)
    return json_success(request)


def delete_saved_snippet(
    request: HttpRequest,
    user_profile: UserProfile,
    *,
    saved_snippet_id: int,
) -> HttpResponse:
    do_delete_saved_snippet(saved_snippet_id, user_profile)
    return json_success(request)

