@dataclass
class MenuItemButton:

    link: str
    title: str
    icon_class: str
    _url: str | None = None
    permissions: Sequence[str] | None = ()
    color: str | None = None

    def __post_init__(self):
        if self.link:
            self._url = reverse_lazy(self.link)

    @property
    def url(self):
        return self._url

    @url.setter
    def url(self, value):
        self._url = value


