    link_text: str
    _url: str | None = None
    permissions: Sequence[str] | None = ()
    auth_required: bool | None = False
    staff_only: bool | None = False
    buttons: Sequence[MenuItemButton] | None = ()

    def __post_init__(self):
        if self.link:
            self._url = reverse_lazy(self.link)

    @property
    def url(self):
        return self._url

    @url.setter
    def url(self, value):
        self._url = value


